import { exactFields, WalletAuthError } from "./canonical.js";

const USER_OPERATION_FIELDS=["sender","nonce","initCode","callData","accountGasLimits","preVerificationGas","gasFees","paymasterAndData","signature"];
const ESTIMATE_FIELDS_REQUIRED=["preVerificationGas","verificationGasLimit","callGasLimit"];
const ESTIMATE_FIELDS_OPTIONAL=["paymasterVerificationGasLimit","paymasterPostOpGasLimit"];
const RECEIPT_REQUIRED=["userOpHash","entryPoint","sender","nonce","actualGasCost","actualGasUsed","success","logs","receipt"];
const RECEIPT_OPTIONAL=["paymaster","reason"];
const METHODS=new Set(["eth_chainId","eth_supportedEntryPoints","eth_estimateUserOperationGas","eth_sendUserOperation","eth_getUserOperationByHash","eth_getUserOperationReceipt"]);

export const ERC_7769_VERSION="ERC-7769";
export const YNX_TESTNET_CHAIN_QUANTITY="0x1917";

export function parsePackedUserOperation(input){exactFields(input,USER_OPERATION_FIELDS,"PackedUserOperation");return Object.freeze({sender:address(input.sender,"sender"),nonce:quantity(input.nonce,"nonce"),initCode:data(input.initCode,"initCode",65536),callData:data(input.callData,"callData",131072),accountGasLimits:dataBytes(input.accountGasLimits,"accountGasLimits",32),preVerificationGas:quantity(input.preVerificationGas,"preVerificationGas"),gasFees:dataBytes(input.gasFees,"gasFees",32),paymasterAndData:data(input.paymasterAndData,"paymasterAndData",65536),signature:nonemptyData(input.signature,"signature",16384)})}

export class ERC7769BundlerClient{
  #endpoint;#entryPoint;#timeoutMs;#maxRequests;#requestTimes=[];#id=0;#headers;
  constructor({endpoint,entryPoint,timeoutMs=10000,maxRequestsPerSecond=10,authentication}={}){
    this.#endpoint=endpointURL(endpoint);this.#entryPoint=address(entryPoint,"entryPoint");
    if(!Number.isSafeInteger(timeoutMs)||timeoutMs<250||timeoutMs>120000)fail("INVALID_CONFIG","Bundler timeout must be between 250 and 120000 ms");
    if(!Number.isSafeInteger(maxRequestsPerSecond)||maxRequestsPerSecond<1||maxRequestsPerSecond>100)fail("INVALID_CONFIG","Bundler local rate limit must be between 1 and 100 requests/second");
    this.#timeoutMs=timeoutMs;this.#maxRequests=maxRequestsPerSecond;this.#headers={"content-type":"application/json","accept":"application/json"};
    if(authentication!==undefined){exactFields(authentication,["header","value"],"Bundler authentication");if(!["authorization","x-api-key"].includes(authentication.header)||typeof authentication.value!=="string"||authentication.value.length<1||authentication.value.length>4096||authentication.value.trim()!==authentication.value)fail("INVALID_CONFIG","Bundler authentication is invalid");this.#headers[authentication.header]=authentication.value}
  }
  async health(){const[chainId,entryPoints]=await Promise.all([this.#request("eth_chainId",[]),this.#request("eth_supportedEntryPoints",[])]);if(chainId!==YNX_TESTNET_CHAIN_QUANTITY)fail("WRONG_NETWORK","Bundler is not connected to YNX Testnet chainId 6423");const parsed=entryPointList(entryPoints);if(!parsed.includes(this.#entryPoint))fail("ENTRY_POINT_UNSUPPORTED","Bundler does not support the configured EntryPoint");return evidence({chainId,entryPoints:parsed},this.#endpoint)}
  async estimateUserOperationGas(operation){const value=await this.#request("eth_estimateUserOperationGas",[parsePackedUserOperation(operation),this.#entryPoint]);return evidence(parseEstimate(value),this.#endpoint)}
  async sendUserOperation(operation){const value=await this.#request("eth_sendUserOperation",[parsePackedUserOperation(operation),this.#entryPoint]);return evidence(hash(value,"userOperationHash"),this.#endpoint)}
  async getUserOperationByHash(userOperationHash){const value=await this.#request("eth_getUserOperationByHash",[hash(userOperationHash,"userOperationHash")]);return evidence(value===null?null:parseByHash(value),this.#endpoint)}
  async getUserOperationReceipt(userOperationHash){const value=await this.#request("eth_getUserOperationReceipt",[hash(userOperationHash,"userOperationHash")]);return evidence(value===null?null:parseReceipt(value),this.#endpoint)}
  async #request(method,params){if(!METHODS.has(method))fail("INVALID_METHOD","Bundler method is unsupported");this.#rateLimit();const id=++this.#id,controller=new AbortController(),timer=setTimeout(()=>controller.abort(),this.#timeoutMs);let response,textBody;try{response=await fetch(this.#endpoint,{method:"POST",headers:this.#headers,body:JSON.stringify({jsonrpc:"2.0",id,method,params}),signal:controller.signal});textBody=await boundedResponseText(response,controller,1048576)}catch(error){if(error instanceof WalletAuthError)throw error;fail(error?.name==="AbortError"?"BUNDLER_TIMEOUT":"BUNDLER_UNAVAILABLE",error?.name==="AbortError"?"Bundler request timed out":"Bundler request failed")}finally{clearTimeout(timer)}if(!response.ok)fail("BUNDLER_HTTP_ERROR",`Bundler returned HTTP ${response.status}`);let body;try{body=JSON.parse(textBody)}catch{fail("BUNDLER_INVALID_RESPONSE","Bundler returned invalid JSON")};if(body?.jsonrpc!=="2.0"||body?.id!==id||typeof body!=="object"||body===null||Array.isArray(body))fail("BUNDLER_INVALID_RESPONSE","Bundler JSON-RPC envelope is invalid");const keys=Object.keys(body).sort().join("\n");if(keys==="error\nid\njsonrpc"){if(typeof body.error?.code!=="number"||typeof body.error?.message!=="string")fail("BUNDLER_INVALID_RESPONSE","Bundler JSON-RPC error is malformed");fail("BUNDLER_RPC_ERROR",`Bundler RPC returned error code ${body.error.code}`)}if(keys!=="id\njsonrpc\nresult")fail("BUNDLER_INVALID_RESPONSE","Bundler JSON-RPC fields are invalid");return body.result}
  #rateLimit(){const now=Date.now();this.#requestTimes=this.#requestTimes.filter(value=>now-value<1000);if(this.#requestTimes.length>=this.#maxRequests)fail("BUNDLER_LOCAL_RATE_LIMIT","Bundler local rate limit exceeded");this.#requestTimes.push(now)}
}

function parseEstimate(value){fields(value,ESTIMATE_FIELDS_REQUIRED,ESTIMATE_FIELDS_OPTIONAL,"Bundler gas estimate");const result={};for(const key of Object.keys(value))result[key]=quantity(value[key],key);return Object.freeze(result)}
function parseByHash(value){fields(value,["userOperation","entryPoint","blockNumber","blockHash","transactionHash"],[],"Bundler UserOperation result");return Object.freeze({userOperation:parsePackedUserOperation(value.userOperation),entryPoint:address(value.entryPoint,"entryPoint"),blockNumber:quantity(value.blockNumber,"blockNumber"),blockHash:hash(value.blockHash,"blockHash"),transactionHash:hash(value.transactionHash,"transactionHash")})}
function parseReceipt(value){fields(value,RECEIPT_REQUIRED,RECEIPT_OPTIONAL,"Bundler UserOperation receipt");if(typeof value.success!=="boolean"||!Array.isArray(value.logs)||typeof value.receipt!=="object"||value.receipt===null||Array.isArray(value.receipt))fail("BUNDLER_INVALID_RESPONSE","Bundler receipt values are invalid");const result={userOpHash:hash(value.userOpHash,"userOpHash"),entryPoint:address(value.entryPoint,"entryPoint"),sender:address(value.sender,"sender"),nonce:quantity(value.nonce,"nonce"),actualGasCost:quantity(value.actualGasCost,"actualGasCost"),actualGasUsed:quantity(value.actualGasUsed,"actualGasUsed"),success:value.success,logs:Object.freeze([...value.logs]),receipt:Object.freeze({...value.receipt})};if("paymaster"in value)result.paymaster=address(value.paymaster,"paymaster");if("reason"in value){if(typeof value.reason!=="string"||value.reason.length>2048)fail("BUNDLER_INVALID_RESPONSE","Bundler receipt reason is invalid");result.reason=value.reason}return Object.freeze(result)}
function entryPointList(value){if(!Array.isArray(value)||value.length<1||value.length>64)fail("BUNDLER_INVALID_RESPONSE","Bundler EntryPoint list is invalid");const parsed=value.map(item=>address(item,"entryPoint"));if(new Set(parsed).size!==parsed.length)fail("BUNDLER_INVALID_RESPONSE","Bundler EntryPoint list contains duplicates");return Object.freeze(parsed)}
function evidence(value,endpoint){return Object.freeze({value,source:endpoint.origin,asOf:new Date().toISOString(),version:ERC_7769_VERSION,authority:"bundler-provider-response"})}
function endpointURL(value){let url;try{url=new URL(value)}catch{fail("INVALID_CONFIG","Bundler endpoint is invalid")};const loopback=url.protocol==="http:"&&["127.0.0.1","localhost","[::1]"].includes(url.hostname);if((url.protocol!=="https:"&&!loopback)||url.username||url.password||url.search||url.hash||url.pathname.endsWith("/")&&url.pathname!=="/")fail("INVALID_CONFIG","Bundler endpoint must be canonical HTTPS (HTTP is loopback-only) without credentials, query or fragment");return url}
function fields(value,required,optional,label){if(typeof value!=="object"||value===null||Array.isArray(value))fail("BUNDLER_INVALID_RESPONSE",`${label} must be an object`);const actual=Object.keys(value),allowed=new Set([...required,...optional]);if(required.some(key=>!(key in value))||actual.some(key=>!allowed.has(key)))fail("BUNDLER_INVALID_RESPONSE",`${label} fields are invalid`)}
async function boundedResponseText(response,controller,limit){const declared=Number(response.headers.get("content-length"));if(Number.isFinite(declared)&&declared>limit){controller.abort();fail("BUNDLER_RESPONSE_TOO_LARGE","Bundler response exceeded one MiB")}if(!response.body)return"";const reader=response.body.getReader(),chunks=[];let total=0;for(;;){const{done,value}=await reader.read();if(done)break;total+=value.byteLength;if(total>limit){controller.abort();fail("BUNDLER_RESPONSE_TOO_LARGE","Bundler response exceeded one MiB")}chunks.push(value)}const bytes=new Uint8Array(total);let offset=0;for(const chunk of chunks){bytes.set(chunk,offset);offset+=chunk.byteLength}return new TextDecoder("utf-8",{fatal:true}).decode(bytes)}
function address(value,label){return pattern(value,label,/^0x[0-9a-f]{40}$/)}function hash(value,label){return pattern(value,label,/^0x[0-9a-f]{64}$/)}function quantity(value,label){return pattern(value,label,/^0x(?:0|[1-9a-f][0-9a-f]*)$/)}function data(value,label,maxBytes){const result=pattern(value,label,/^0x(?:[0-9a-f]{2})*$/);if((result.length-2)/2>maxBytes)fail("INVALID_USER_OPERATION",`${label} exceeds its byte limit`);return result}function nonemptyData(value,label,maxBytes){const result=data(value,label,maxBytes);if(result==="0x")fail("INVALID_USER_OPERATION",`${label} cannot be empty`);return result}function dataBytes(value,label,bytes){return pattern(value,label,new RegExp(`^0x[0-9a-f]{${bytes*2}}$`))}function pattern(value,label,regex){if(typeof value!=="string"||!regex.test(value))fail("INVALID_FIELD",`${label} is invalid`);return value}function fail(code,message){throw new WalletAuthError(code,message)}
